// Synthetic YOLOX-style row: [x y w h objectness class...].
out = zeros(1, 85);
out(1, 1:5) = [0.5 0.5 0 0 0.9];
out(1, 8) = 0.8;
detections = dnn_decode_yolo(out, [640 480], 0.25, 0.45, "yolox", [640 640], [8 16 32]);
image = uint8(zeros(480, 640, 3));
imshow_detections(image, detections);
